    46→          current_token += '%';
    47→          pos++;
    48→          continue;
    49→        }
    50→      }
    51→
    52→      if (!current_token.empty()) {
    53→        formatters.emplace_back(FormatterProviderBasePtr<FormatterContext>{
    54→            new PlainStringFormatterBase<FormatterContext>(current_token)});
